+    let child_id = create_issue_id(&workspace, "Issue 198 Close Child", "issue_198_close_child");
+
+    let add_dep = run_br(
+        &workspace,
+        ["dep", "add", &child_id, &parent_id, "--json"],
+        "issue_198_close_dep_add",
+    );
+    assert!(
+        add_dep.status.success(),
+        "dep add failed: stdout={} stderr={}",
+        add_dep.stdout,
+        add_dep.stderr
