+
+    reimport_workspace_db_from_jsonl(&workspace, "issue_198_close");
+
+    let close = run_br(
+        &workspace,
+        ["close", &parent_id, "--reason", "regression-test", "--json"],
+        "issue_198_close_command",
+    );
